raw_response:
{
  "prompt": "தாவரங்கள் சூரிய ஒளியைப் பயன்படுத்தி எப்படித் தங்களுக்குத் தேவையான உணவைத் தயாரித்துக் கொள்கின்றன என்பதை, ஒரு பத்து வயதுக் குழந்தைக்குப் புரியும் வகையில் மூன்று அல்லது நான்கு வரிகளில் விளக்கி எழுதுங்கள்.",
  "expected": "தாவரங்கள் சூரிய ஒளி, காற்று மற்றும் தண்ணீரைப் பயன்படுத்தித் தங்களுக்குத் தேவையான உணவைத் தாங்களே தயாரித்துக்கொள்ளும் முறைக்கு ஒளிச்சேர்க்கை என்று பெயர். செடிகளின் இலைகளில் உள்ள பச்சையம் என்ற நிறமி, சூரிய ஒளியை ஈர்த்து அந்த ஆற்றலை உணவாக மாற்றுகிறது. இந்தச் செயல்பாட்டின் மூலம் தாவரங்கள் சர்க்கரையைத் தயாரித்து வளர்வதற்குப் பயன்படுத்துகின்றன, மேலும் நமக்குத் தேவையான ஆக்சிஜனை வெளியிடுகின்றன."
}

{
"prompt": "ஒரு சிறந்த தலைவருக்கு இருக்க வேண்டிய பண்புகள் என்னென்ன என்பதை விளக்குக. உங்கள் விளக்கத்தை இரண்டு தெளிவான உதாரணங்களுடன் விவரிக்கவும்.",
"expected": "ஒரு சிறந்த தலைவர் என்பவர் மற்றவர்களுக்கு முன்மாதிரியாகத் திகழ்பவர். இதற்கு இரண்டு உதாரணங்கள்: முதலாவதாக, ஒரு நெருக்கடியான சூழலில் குழுவினர் பதற்றமடையும் போது, அமைதியாகச் செயல்பட்டு சரியான முடிவுகளை எடுக்கும் திறன். இரண்டாவதாக, தனது குழுவில் உள்ளவர்களின் திறமைகளை அடையாளம் கண்டு, அவர்களுக்கு ஊக்கமளித்து, அவர்களின் வளர்ச்சிக்குத் தடையாக இருக்கும் தடைகளை நீக்கும் பண்பு. இத்தகைய குணங்களே ஒருவரைச் சிறந்த தலைவராக மாற்றுகின்றன."
}

{
  "prompt": "வானிலைக்கும் காலநிலைக்கும் இடையே உள்ள வேறுபாட்டை மூன்று வாக்கியங்களில் விளக்குக.",
  "expected": "வானிலை என்பது ஒரு குறிப்பிட்ட இடத்தில் குறுகிய காலத்தில் நிலவும் வளிமண்டல மாற்றங்களைக் குறிப்பதாகும். காலநிலை என்பது ஒரு குறிப்பிட்ட பகுதியில் நீண்ட காலத்திற்கு நிலவும் வானிலை மாற்றங்களின் சராசரி நிலையாகும். சுருக்கமாகச் சொன்னால், வானிலை என்பது அன்றாட நிகழ்வு, ஆனால் காலநிலை என்பது பல ஆண்டுகளின் ஒட்டுமொத்த சராசரி வடிவமாகும்."
}

{
"prompt": "உங்கள் ஆசிரியருக்கு ஒரு மின்னஞ்சல் எழுதுங்கள். அதில், நீங்கள் சமர்ப்பிக்க வேண்டிய வீட்டுப் பாடத்தை முடிப்பதற்கு கூடுதலாக ஒரு வாரம் அவகாசம் கேட்டு, பணிவாகவும் மரியாதையாகவும் கோரிக்கை விடுங்கள்.",
"expected": "மதிப்பிற்குரிய ஐயா/அம்மா, வணக்கம். நான் உங்கள் வகுப்பில் பயிலும் மாணவன். வரும் திங்கள்கிழமை சமர்ப்பிக்க வேண்டிய வீட்டுப் பாடத்தை முடிக்க எனக்கு கூடுதல் நேரம் தேவைப்படுகிறது. சில தவிர்க்க முடியாத காரணங்களால் என்னால் குறித்த நேரத்தில் அதை முடிக்க இயலவில்லை. எனவே, எனக்கு மேலும் ஒரு வாரம் கால அவகாசம் வழங்கி உதவினால் மிக்க உதவியாக இருக்கும். தங்களின் புரிதலுக்கு நன்றி. இப்படிக்கு, தங்கள் உண்மையுள்ள, [மாணவர் பெயர்]."
}

{
  "prompt": "ஒளிச்சேர்க்கை என்றால் என்ன என்பதை பத்து வயது சிறுவன் எளிதாகப் புரிந்துகொள்ளும் வகையில் மூன்று அல்லது நான்கு வாக்கியங்களில் விளக்கி எழுதுங்கள்.",
  "expected": "தாவரங்கள் தங்களுக்குத் தேவையான உணவைத் தாங்களே தயாரித்துக்கொள்ளும் முறைக்கு ஒளிச்சேர்க்கை என்று பெயர். சூரிய ஒளி, காற்று மற்றும் தண்ணீரைப் பயன்படுத்தி, தாவரங்கள் தங்கள் இலைகளில் உள்ள பச்சையத்தின் உதவியுடன் சர்க்கரையை உணவாக உருவாக்குகின்றன. இந்தச் செயல்பாட்டின் போது, தாவரங்கள் நாம் சுவாசிக்கத் தேவையான ஆக்சிஜனை வெளியிடுகின்றன. இதனால் தான் செடி கொடிகள் பூமியில் உயிர்கள் வாழ்வதற்கு மிக முக்கியமானதாக இருக்கின்றன."
}

{
"prompt": "புதிதாக ஒரு மொழியைக் கற்கத் தொடங்கும் ஒருவருக்கு உதவும் வகையில், நடைமுறைக்கு ஒத்துவரும் மூன்று ஆலோசனைகளை வழங்கவும்.",
"expected": "புதிதாக ஒரு மொழியைக் கற்கத் தொடங்கும் போது, அந்த மொழியில் உள்ள எளிமையான பாடல்கள் அல்லது குறுகிய காணொளிகளைக் கேட்டுப் பழகலாம். தினமும் குறைந்தது பத்து புதிய சொற்களையாவது கற்றுக்கொண்டு, அவற்றை அன்றாடப் பேச்சில் பயன்படுத்த முயற்சிப்பது நல்ல பலனைத் தரும். இறுதியாக, இலக்கணத்தைப் பற்றி மட்டும் கவலைப்படாமல், பிழைகள் ஏற்பட்டாலும் தயங்காமல் அந்த மொழியில் பேசத் தொடங்குவது கற்றலை வேகப்படுத்தும்."
}

{
"prompt": "ஒரு சிறந்த தலைவருக்கு இருக்க வேண்டிய பண்புகள் யாவை என்பதை விளக்கி, அதற்கு இரண்டு பொருத்தமான உதாரணங்களைத் தருக.",
"expected": "ஒரு சிறந்த தலைவர் என்பவர் மற்றவர்களுக்கு முன்மாதிரியாகத் திகழ்பவர். இதற்கு இரண்டு உதாரணங்கள்: முதலாவதாக, ஒரு குழுவின் இலக்கை அடையத் தன்னையும் ஈடுபடுத்திக்கொண்டு, மற்றவர்களின் கருத்துகளுக்கு மதிப்பளிக்கும் ஒரு மேலாளர். இரண்டாவதாக, நெருக்கடியான நேரங்களில் பதற்றமடையாமல், தனது குழுவினருக்கு நம்பிக்கையூட்டி, சரியான முடிவுகளை எடுக்கும் ஒரு விளையாட்டு அணியின் கேப்டன்."
}

{
"prompt": "பாரம்பரிய மந்திர தந்திரங்கள் இல்லாத, முற்றிலும் மாறுபட்ட ஐந்து கற்பனை நாவல் கதைக் கருக்களைப் பரிந்துரைக்கவும்.",
"expected": "1. தொழில்நுட்பம் மற்றும் இயற்கை சக்திகள் ஒன்றிணைந்த ஒரு உலகம்: இதில் மந்திரத்திற்குப் பதிலாக, பழங்கால இயந்திரங்களை இயக்குவதற்கு மனிதர்களின் உணர்ச்சிகள் அல்லது நினைவுகள் எரிபொருளாகப் பயன்படுத்தப்படுகின்றன. 2. கனவுகளின் மூலம் இயங்கும் உலகம்: மக்கள் விழித்திருக்கும்போது சாதாரண மனிதர்களாக இருப்பார்கள், ஆனால் தூங்கும்போது அவர்கள் காணும் கனவுகள் நிஜ உலகில் மாற்றங்களை ஏற்படுத்தும். 3. மொழியால் உருவான உலகம்: இந்த உலகில் ஒலிகள் மற்றும் சொற்களுக்கு அதீத ஆற்றல் உண்டு. சில குறிப்பிட்ட ஒலிகளை உச்சரிப்பதன் மூலம் பொருட்களை நகர்த்தவோ அல்லது காலநிலையை மாற்றவோ முடியும். 4. நிழல்களின் உலகம்: ஒவ்வொரு மனிதனுக்கும் ஒரு நிழல் உண்டு, அந்த நிழல்கள் தனித்து இயங்கக்கூடியவை. மனிதர்களுக்கும் நிழல்களுக்கும் இடையிலான ஒப்பந்தங்கள் மற்றும் போராட்டங்களே அந்த உலகின் அடிப்படை. 5. காலத்தை உணவாகக் கொள்ளும் உலகம்: மக்கள் ஒருவருக்கொருவர் காலத்தை பரிமாறிக்கொள்ளும் விசித்திரமான சமூகம். நீண்ட காலம் வாழ வேண்டுமானால், மற்றவர்களிடமிருந்து காலத்தை திருட வேண்டும் அல்லது சம்பாதிக்க வேண்டும்."
}

{
"prompt": "கடுமையான சைவ உணவை மட்டுமே உட்கொள்ளும் ஒரு தொழில்முறை விளையாட்டு வீரருக்கு, சத்துக்கள் நிறைந்த ஒரு சீரான உணவுத் திட்டத்தை உருவாக்கித் தருக.",
"expected": "காலை உணவு: ஓட்ஸ் கஞ்சி, பாதாம் பருப்பு, மற்றும் பெர்ரி பழங்கள் கலந்த உணவுக் கலவை. மதிய உணவு: குயினோவா (Quinoa) அல்லது பழுப்பு நிற அரிசி, வேகவைத்த கொண்டைக்கடலை, மற்றும் கீரை வகைகள் சேர்த்த சாலட். மாலை நேர சிற்றுண்டி: வேர்க்கடலை வெண்ணெய் தடவிய முழு தானிய ரொட்டி மற்றும் ஒரு வாழைப்பழம். இரவு உணவு: டோஃபு (Tofu) சேர்த்த காய்கறி சூப் மற்றும் நீராவியில் வேகவைத்த காய்கறிகள். இந்த உணவுத் திட்டத்தில் புரதம், கார்போஹைட்ரேட் மற்றும் ஆரோக்கியமான கொழுப்புகள் சரியான விகிதத்தில் இருப்பதை உறுதி செய்ய வேண்டும்."
}

{
"prompt": "நவீன போர்முறையில் தானியங்கி ஆயுத அமைப்புகளைப் பயன்படுத்துவது குறித்து நிலவும் முக்கிய அறநெறி சார்ந்த ஆதரவு மற்றும் எதிர்ப்பு வாதங்களைச் சுருக்கமாக விளக்குக.",
